mapper.select:
/* 활동 카테고리별 다음날 에너지 변화량 평균 분석 */
SELECT category FROM (
    SELECT i.category, AVG(l_next.energy - l_curr.energy) as avg_boost
    FROM done_item i
    JOIN daily_log l_curr ON i.log_date = l_curr.log_date
    JOIN daily_log l_next ON i.log_date + 1 = l_next.log_date
    WHERE i.log_date BETWEEN #{startDate} AND #{endDate}
    GROUP BY i.category
    ORDER BY avg_boost DESC
) WHERE ROWNUM = 1
